@extends('layouts.hiddenOther')
@section('content')
    <div class="container">
        <section class="contacts">
            <h2>{{$page->title}}</h2>
            <div class="contacts__sales">
                <ul>
                    @foreach(iblock()->getById(12)?->elements as $element)
                        <li>
                            {{$element->title}}
                            @if($element->props['mail'])
                                <a class="mail" href="mailto:{!! $element->props['mail'] !!}">{!! $element->props['mail'] !!}</a>
                            @endif
                            @if( $element->props['phone'])
                                <a class="phone" href="tel:{!! $element->props['phone'] !!}">{!! $element->props['phone'] !!}</a>
                            @endif
                        </li>
                    @endforeach
                </ul>
            </div>
            <div class="contacts__content">
                <div id="map">
                    {!! iblock()->getById(10)?->elements[0]->props['map']  !!}
                </div>
                <div class="contacts__info">
                    @if(settings('monday'))
                        <div>
                            <span>Время работы</span>
                            <p>{{settings('monday')}}</p>
                        </div>
                    @endif
                    @if(settings('address'))
                        <div>
                            <span>Адрес</span>
                            <p>{{settings('address')}}</p>
                            <p>
                                Доехать по карте:
                            </p>
